import Link from "next/link";
import Image from "next/image";
import { scrapeVessels } from "../lib/scraper";
import { cleanData } from "../lib/clean";
import { Vessel } from "../lib/types";

export default async function AuctionsPage({
  searchParams,
}: {
  searchParams?: { query?: string };
}) {
  const query = searchParams?.query?.toLowerCase() || "";
  const raw = await scrapeVessels();
  let vessels = cleanData(raw);

  if (query) {
    vessels = vessels.filter((v: Vessel) =>
      v.name.toLowerCase().includes(query) ||
      (v.location && v.location.toLowerCase().includes(query))
    );
  }

  return (
    <div className="container mx-auto px-6 py-12">
      <h1 className="text-3xl font-bold text-[#0f2846] mb-8 border-b pb-4">
        {query ? `Search Results for "${searchParams?.query}"` : "Active Auctions"}
      </h1>

      {vessels.length === 0 ? (
        <p className="text-gray-500 text-lg">No vessels found matching your search.</p>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {vessels.map((vessel: Vessel) => (
          <Link
            key={vessel.id}
            href={`/vessels/${vessel.id}`}
            className="bg-white shadow rounded-lg p-4 hover:shadow-lg transition"
          >
            <Image
              src={vessel.image || "https://via.placeholder.com/300"}
              alt={vessel.name || "Vessel"}
              width={400}
              height={160}
              className="h-40 w-full object-cover rounded"
              unoptimized
            />

            <h2 className="font-bold mt-2">{vessel.name}</h2>
            <p className="text-sm text-gray-500">{vessel.location}</p>
            <p className="text-blue-600 font-semibold">{vessel.price}</p>
          </Link>
        ))}
        </div>
      )}
    </div>
  );
}